interface ErrorPresentationPayload {
  title: string;
  description: string;
  variant: 'destructive';
}

type ErrorPresenter = (payload: ErrorPresentationPayload) => void;

export function setErrorPresenter(presenter: ErrorPresenter | null): void {
  if (!presenter) {
    configureErrorNotifier(null);
    return;
  }

  configureErrorNotifier(({ title, description }) => {
    presenter({
      title,
      description,
      variant: 'destructive',
    });
  });
}


